class Solution:
    def numberOfArithmeticSlices(self, nums):
        n = len(nums)
        total = 0
        for i in range(n):
            for j in range(i):
                d = nums[i] - nums[j]
                # extend any arithmetic subsequence ending (..., nums[j]) with step d
                # depth-first count of valid (length>=3) completions through this pair
                stack = [(j, 2)]
                while stack:
                    k, length = stack.pop()
                    if length >= 3:
                        total += 1
                    for p in range(k):
                        if nums[k] - nums[p] == d:
                            stack.append((p, length + 1))
        return total

