class Solution:
    def numberOfArithmeticSlices(self, nums):
        n = len(nums)
        dp = [dict() for _ in range(n)]
        total = 0
        for i in range(n):
            for j in range(i):
                d = nums[i] - nums[j]
                cnt_j = dp[j].get(d, 0)
                total += cnt_j
                dp[i][d] = dp[i].get(d, 0) + cnt_j + 1
        return total

