var numberOfArithmeticSlices = function(nums) {
    const n = nums.length;
    const dp = Array.from({ length: n }, () => new Map());
    let total = 0;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < i; j++) {
            const d = nums[i] - nums[j];
            const cntJ = dp[j].get(d) || 0;
            total += cntJ;
            dp[i].set(d, (dp[i].get(d) || 0) + cntJ + 1);
        }
    }
    return total;
};
